  let stripped = 0;
  while (messages.length > 0) {
    const last = messages[messages.length - 1];
    if (last.role === "assistant" && (!last.content || last.content === "")) {
      messages.pop();
      stripped++;
    } else {
      break;
    }
  }
  if (stripped > 0)
    adjustments.push(`stripped:${stripped}-trailing-empty-assistant`);
