function pickViaInput() {
  return new Promise((resolve, reject) => {
    const input = document.createElement("input");
    input.type = "file";
    input.accept = ACCEPT_EXTENSIONS2.join(",");
    input.style.display = "none";
    document.body.appendChild(input);
    let settled = false;
    const done = (result, err) => {
      if (settled)
        return;
      settled = true;
      try {
        document.body.removeChild(input);
      } catch {}
      if (err)
        reject(err);
      else
        resolve(result);
    };
    input.addEventListener("change", () => {
      const file = input.files?.[0];
      if (!file)
        return done(null);
      file.arrayBuffer().then((ab) => done({ name: file.name, bytes: new Uint8Array(ab) }), (err) => done(null, err));
    });
    input.addEventListener("cancel", () => done(null));
    input.click();
  });
}
function pickLorebookFile() {
  return new Promise((resolve, reject) => {
    const input = document.createElement("input");
    input.type = "file";
    input.accept = ".json,.lorebook,application/json";
    input.style.display = "none";
    document.body.appendChild(input);
    let settled = false;
    const done = (f, err) => {
      if (settled)
        return;
      settled = true;
      try {
        document.body.removeChild(input);
      } catch {}
      if (err)
        reject(err);
      else
        resolve(f);
    };
    input.addEventListener("change", () => {
      const list = input.files;
      done(list && list.length > 0 ? list.item(0) : null);
    });
    input.addEventListener("cancel", () => done(null));
    input.click();
  });
}
function bytesToBase643(bytes) {
  let binary = "";
  const chunk = 32768;
  for (let i = 0;i < bytes.length; i += chunk) {
    binary += String.fromCharCode(...bytes.subarray(i, i + chunk));
  }
  return btoa(binary);
}
function generateSessionId2() {
  const c = typeof globalThis !== "undefined" ? globalThis.crypto : undefined;
  if (c?.randomUUID)
    return c.randomUUID();
  return `mod-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 10)}`;
}

